import { useRef } from 'react';
import { useIntersectionObserver } from './useIntersectionObserver';

export default function App() {
  const ref = useRef<HTMLDivElement>(null);
  const { isIntersecting } = useIntersectionObserver(ref, { threshold: 0.5 });

  return (
    <div className="p-8">
      <p className="mb-4 text-sm text-gray-500">Scroll down to reveal the box</p>
      <div style={{ height: '120vh' }} />
      <div
        ref={ref}
        style={{
          padding: '2rem',
          border: '2px solid',
          borderColor: isIntersecting ? '#22c55e' : '#6b7280',
          borderRadius: '0.5rem',
          textAlign: 'center',
          transition: 'border-color 0.3s, opacity 0.3s',
          opacity: isIntersecting ? 1 : 0.3,
        }}
      >
        {isIntersecting ? '✅ Visible!' : '👆 Scroll to see me'}
      </div>
    </div>
  );
}

