solutionCode.useIntersectionObserver.ts:
import { type RefObject, useEffect, useState } from 'react';

interface IntersectionResult {
  isIntersecting: boolean;
  entry: IntersectionObserverEntry | null;
}

export function useIntersectionObserver(
  ref: RefObject<Element | null>,
  options: IntersectionObserverInit = {},
): IntersectionResult {
  const [result, setResult] = useState<IntersectionResult>({
    isIntersecting: false,
    entry: null,
  });

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        setResult({ isIntersecting: entry.isIntersecting, entry });
      },
      options,
    );

    observer.observe(element);
    return () => observer.disconnect();
    // options spread intentionally omitted from deps — callers should memoize
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [ref]);

  return result;
}
